// build INSERT payment_summaries + UPDATE payments
const b = $json.body || {};
const chargeIds = Array.isArray(b.charge_ids) ? b.charge_ids : [];
if (chargeIds.length === 0) throw new Error('charge_ids required');
const now = new Date();
const yy = String((now.getFullYear() + 543) % 100).padStart(2, '0');
const mm = String(now.getMonth() + 1).padStart(2, '0');
const dd = String(now.getDate()).padStart(2, '0');
const seq = Math.floor(Math.random() * 900 + 100);
const summaryNo = b.summary_no || `SU${yy}${mm}${dd}${seq}`;
const escape = (s) => String(s || '').replace(/'/g, "''");
const breakdown = JSON.stringify(b.breakdown || []).replace(/'/g, "''");
const chargeList = chargeIds.map(c => `'${escape(c)}'`).join(',');
return [{
  json: {
    summary_no: summaryNo,
    date_from: b.date_from || null,
    date_to: b.date_to || null,
    group_by: b.group_by || '',
    total_amount: Number(b.total_amount) || 0,
    total_count: Number(b.total_count) || chargeIds.length,
    breakdown: breakdown,
    note: escape(b.note),
    branch_code: escape(b.branch_code),
    branch_name: escape(b.branch_name),
    created_by: escape(b.created_by),
    charge_list: chargeList,
    charge_ids: chargeIds
  }
}];
